DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "niceTables.pl", "parserRadioButtons.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("LimitedNumeric"); $yesno=RadioButtons([ "So -3 is a solution to this equation.", "So -3 is not a solution to this equation.", ], 1, showInStatic => 0 );
############################################################ # Body ############################################################
BEGIN_PGML Is [`-3`] a solution to the equation [`2x-3=5-(4+x)\text{?}`]
>> [@DataTable( [ [PGML('[`2x-3`]'), PGML('[`{}={}`]'), PGML('[`5-(4+x)`]'), ], [PGML('[_]{-9}{3}'), PGML('[`{}\wonder{=}{}`]'), PGML('[_]{4}{3}'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$yesno}{5}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION We have to substitute [`-3`] in for [`x`] and simplify each side:
[```\newcommand{\highlight}[1]{\mathchoice{\colorbox{lightsapphire}{$\displaystyle #1$}}{\colorbox{lightsapphire}{$\textstyle #1$}}{\colorbox{lightsapphire}{$\scriptstyle #1$}}{\colorbox{lightsapphire}{$\scriptscriptstyle #1$}}}\newcommand{\substitute}[1]{{\color{blue}{{#1}}}}\newcommand{\reject}[1]{\stackrel{\text{no}}{#1}}\newcommand{\wonder}[1]{\stackrel{\text{?}}{#1}}\newcommand{\amp}{&} \begin{aligned} 2x-3\amp=5-(4+x)\\ 2(\substitute{-3})-3\amp\wonder{=}5-(4+(\substitute{-3}))\\ \highlight{-6}-3\amp\wonder{=} 5-(\highlight{1})\\ \highlight{-9}\amp\reject{=}\highlight{4} \end{aligned} ```]
Since [`-9=4`] is false, [`-3`] is not a solution to this equation.
END_PGML_SOLUTION
############################################################ # End Problem ############################################################
